```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Shipment>(e =>
        {
            e.HasIndex(s => s.TrackingNumber).IsUnique();
        });
    }
}
```

### 5. Create API endpoints

Add shipment API endpoints to `Program.cs` in the server project. Add them before `app.Run()`. Create a separate file for the endpoints:

Create `/tmp/sv-4fb57d53d4ea4a95adc69278b15818e2/ShipmentTracker/ShipmentTracker/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    ActualDelivery = s.ActualDelivery,
                    RecipientName = s.RecipientName,
                    CustomerEmail = s.CustomerEmail,
                    Notes = s.Notes
                })
                .ToListAsync();
            return Results.Ok(shipments);
        });

        group.MapGet("/{id:int}", async (int id, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(ToDto(shipment));
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(ToDto(shipment));
        });

        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = dto.Status,
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                ActualDelivery = dto.ActualDelivery,
                RecipientName = dto.RecipientName,
                CustomerEmail = dto.CustomerEmail,
                Notes = dto.Notes
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", ToDto(shipment));
        });

        group.MapPut("/{id:int}", async (int id, ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Origin = dto.Origin;
            shipment.Destination = dto.Destination;
            shipment.Status = dto.Status;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            shipment.ActualDelivery = dto.ActualDelivery;
            shipment.RecipientName = dto.RecipientName;
            shipment.CustomerEmail = dto.CustomerEmail;
            shipment.Notes = dto.Notes;

            await db.SaveChangesAsync();
            return Results.Ok(ToDto(shipment));
        });

        group.MapDelete("/{id:int}", async (int id, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    };
}
```

