    private string statusFilter = "";
    private string searchTerm = "";
    private bool showForm;
    private ShipmentDto editingShipment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
        ApplyFilter();
    }

    private void ApplyFilter()
    {
        if (shipments is null) return;

        filteredShipments = shipments.Where(s =>
        {
            if (!string.IsNullOrEmpty(statusFilter) && s.Status.ToString() != statusFilter)
                return false;
            if (!string.IsNullOrEmpty(searchTerm) &&
                !s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) &&
                !s.RecipientName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) &&
                !s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
                return false;
            return true;
        }).ToList();
    }

    private void ShowCreateForm()
    {
        editingShipment = new ShipmentDto
        {
            TrackingNumber = $"TRK-{DateTime.UtcNow:yyyy}-{Random.Shared.Next(100, 999)}",
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = DateTime.UtcNow.AddDays(5),
            Status = ShipmentStatus.Pending
        };
