```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        var response = await http.GetAsync($"/api/shipments/{id}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }

    public async Task<ShipmentDto?> UpdateShipmentAsync(int id, ShipmentDto shipment)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}", shipment);
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task DeleteShipmentAsync(int id)
    {
        await http.DeleteAsync($"/api/shipments/{id}");
    }
}
```

### 9. Implement server-side service using DbContext directly

Create `/tmp/sv-4fb57d53d4ea4a95adc69278b15818e2/ShipmentTracker/ShipmentTracker/Services/ServerShipmentService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = s.Status,
                ShippedDate = s.ShippedDate,
                EstimatedDelivery = s.EstimatedDelivery,
                ActualDelivery = s.ActualDelivery,
                RecipientName = s.RecipientName,
                CustomerEmail = s.CustomerEmail,
                Notes = s.Notes
            })
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        var s = await db.Shipments.FindAsync(id);
        return s is null ? null : ToDto(s);
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);
        return s is null ? null : ToDto(s);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = dto.TrackingNumber,
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = dto.Status,
            ShippedDate = dto.ShippedDate,
            EstimatedDelivery = dto.EstimatedDelivery,
            ActualDelivery = dto.ActualDelivery,
            RecipientName = dto.RecipientName,
            CustomerEmail = dto.CustomerEmail,
            Notes = dto.Notes
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task<ShipmentDto?> UpdateShipmentAsync(int id, ShipmentDto dto)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return null;

        shipment.Origin = dto.Origin;
        shipment.Destination = dto.Destination;
        shipment.Status = dto.Status;
        shipment.EstimatedDelivery = dto.EstimatedDelivery;
        shipment.ActualDelivery = dto.ActualDelivery;
        shipment.RecipientName = dto.RecipientName;
        shipment.CustomerEmail = dto.CustomerEmail;
        shipment.Notes = dto.Notes;

        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task DeleteShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
        }
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    };
}
```

