            @* Status progress bar *@
            <div class="mt-3">
                <h5>Progress</h5>
                <div class="d-flex justify-content-between position-relative mt-3 mb-2">
                    @{
                        var stages = new[] {
                            ShipmentStatus.Pending,
                            ShipmentStatus.PickedUp,
                            ShipmentStatus.InTransit,
                            ShipmentStatus.OutForDelivery,
                            ShipmentStatus.Delivered
                        };
                        var currentStage = Array.IndexOf(stages, shipment.Status);
                        if (currentStage < 0) currentStage = 2; // Delayed/Returned shown at InTransit level
                    }
                    @for (int i = 0; i < stages.Length; i++)
                    {
                        var isActive = i <= currentStage;
                        var isCurrent = i == currentStage;
                        <div class="text-center" style="flex: 1;">
                            <div class="rounded-circle d-inline-flex align-items-center justify-content-center @(isActive ? "bg-primary text-white" : "bg-light text-muted border")"
