@code {
    private List<ShipmentDto>? shipments;
    private List<ShipmentDto> filteredShipments = [];
    private string statusFilter = "";
    private string searchTerm = "";
    private bool showForm;
    private ShipmentDto editingShipment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
        ApplyFilter();
    }

    private void ApplyFilter()
    {
        if (shipments is null) return;

        filteredShipments = shipments.Where(s =>
        {
            if (!string.IsNullOrEmpty(statusFilter) && s.Status.ToString() != statusFilter)
                return false;
            if (!string.IsNullOrEmpty(searchTerm) &&
                !s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) &&
                !s.RecipientName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) &&
                !s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
                return false;
            return true;
        }).ToList();
    }

    private void ShowCreateForm()
    {
        editingShipment = new ShipmentDto
        {
            TrackingNumber = $"TRK-{DateTime.UtcNow:yyyy}-{Random.Shared.Next(100, 999)}",
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = DateTime.UtcNow.AddDays(5),
            Status = ShipmentStatus.Pending
        };
        showForm = true;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        editingShipment = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            ActualDelivery = shipment.ActualDelivery,
            RecipientName = shipment.RecipientName,
            CustomerEmail = shipment.CustomerEmail,
            Notes = shipment.Notes
        };
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (editingShipment.Id == 0)
        {
            await ShipmentService.CreateShipmentAsync(editingShipment);
        }
        else
        {
            await ShipmentService.UpdateShipmentAsync(editingShipment.Id, editingShipment);
        }
        showForm = false;
        await LoadShipments();
    }

    private void CancelEdit()
    {
        showForm = false;
    }

    private async Task DeleteShipment(int id)
    {
        await ShipmentService.DeleteShipmentAsync(id);
        await LoadShipments();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
