                   @bind="trackingNumber" @onkeyup="HandleKeyUp" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (notFound)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>". Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h4 class="mb-0">Shipment @shipment.TrackingNumber</h4>
            <span class="badge fs-6 @GetStatusBadge(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <h5>Shipment Details</h5>
                    <table class="table">
                        <tbody>
                            <tr>
                                <th>Origin</th>
                                <td>@shipment.Origin</td>
                            </tr>
                            <tr>
                                <th>Destination</th>
                                <td>@shipment.Destination</td>
                            </tr>
                            <tr>
                                <th>Recipient</th>
                                <td>@shipment.RecipientName</td>
                            </tr>
                            @if (!string.IsNullOrEmpty(shipment.Notes))
                            {
                                <tr>
                                    <th>Notes</th>
                                    <td>@shipment.Notes</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
                <div class="col-md-6">
                    <h5>Delivery Timeline</h5>
                    <table class="table">
                        <tbody>
                            <tr>
                                <th>Shipped Date</th>
                                <td>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</td>
                            </tr>
                            <tr>
                                <th>Estimated Delivery</th>
                                <td>
                                    <strong>@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</strong>
                                    @{
                                        var daysRemaining = (shipment.EstimatedDelivery - DateTime.UtcNow).Days;
                                    }
                                    @if (shipment.Status != ShipmentStatus.Delivered && daysRemaining >= 0)
                                    {
                                        <br /><small class="text-muted">@daysRemaining day(s) remaining</small>
                                    }
                                </td>
                            </tr>
                            @if (shipment.ActualDelivery.HasValue)
                            {
                                <tr>
                                    <th>Actual Delivery</th>
                                    <td class="text-success">
                                        <strong>@shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</strong>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>

            @* Status progress bar *@
            <div class="mt-3">
                <h5>Progress</h5>
                <div class="d-flex justify-content-between position-relative mt-3 mb-2">
                    @{
                        var stages = new[] {
                            ShipmentStatus.Pending,
                            ShipmentStatus.PickedUp,
                            ShipmentStatus.InTransit,
                            ShipmentStatus.OutForDelivery,
                            ShipmentStatus.Delivered
                        };
                        var currentStage = Array.IndexOf(stages, shipment.Status);
                        if (currentStage < 0) currentStage = 2; // Delayed/Returned shown at InTransit level
                    }
                    @for (int i = 0; i < stages.Length; i++)
                    {
                        var isActive = i <= currentStage;
                        var isCurrent = i == currentStage;
                        <div class="text-center" style="flex: 1;">
                            <div class="rounded-circle d-inline-flex align-items-center justify-content-center @(isActive ? "bg-primary text-white" : "bg-light text-muted border")"
                                 style="width: 36px; height: 36px; font-weight: bold;">
                                @if (isActive && !isCurrent)
                                {
                                    <span>✓</span>
                                }
                                else
                                {
                                    <span>@(i + 1)</span>
                                }
                            </div>
                            <div class="small mt-1 @(isActive ? "fw-bold" : "text-muted")">@stages[i]</div>
                        </div>
                    }
                </div>
                @if (shipment.Status == ShipmentStatus.Delayed)
                {
                    <div class="alert alert-danger mt-2 mb-0">
                        ⚠ This shipment is currently delayed. Estimated delivery has been updated.
                    </div>
                }
                @if (shipment.Status == ShipmentStatus.Returned)
                {
                    <div class="alert alert-dark mt-2 mb-0">
                        ↩ This shipment has been returned to the sender.
                    </div>
                }
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
